import axios from 'axios'
import type {
    IAddressFormatResults,
    IAddressSearchResults,
    ICountrySearchResults,
    IEmailSearchResults,
    IPhoneValidationResults
} from '@lmb-it/kitsconcerto-types'

const Lookup_URL: string = 'https://api.experianaperture.io/'
/*const LookupEnum: { ADDRESS: string; PHONE: string; EMAIL: string; } = {
    ADDRESS: 'address',
    PHONE: 'phone',
    EMAIL: 'email'
}*/

class Experian {
  
  API_KEY='';
  
  constructor(API_KEY:string) {
    this.API_KEY = API_KEY;
  }
  searchAddress: IAddressSearchResults = async (pSearchTerm: string, pCountryISO = 'AUS') => {
    //, pDataSet = []) {
    const mData = {
      country_iso: pCountryISO,
      max_suggestions: 5,
      // "datasets": pDataSet,
      components: {
        unspecified: [pSearchTerm]
      }
    }
    return await this.sendRequest('POST', `${Lookup_URL}address/search/v1`, mData)
  }
  getDataSetForCountry: ICountrySearchResults = async (pCountryISO = 'AUS') => {
    return await this.sendRequest('GET', `${Lookup_URL}address/datasets/v1`, {country_iso: pCountryISO})
  }
  formatAddress: IAddressFormatResults = async (pGlobalAddressKey: any) => {
    return await this.sendRequest('GET', `${Lookup_URL}address/format/v1`, pGlobalAddressKey, {'Add-Components': true})
  }
  validateEmail: IEmailSearchResults = async (pEmail: any) => {
    const mData = {
      email: pEmail
    }
    return await this.sendRequest('POST', `${Lookup_URL}email/validate/v2`, mData, {'Add-Metadata': true})
  }
  validatePhoneNumber: IPhoneValidationResults = async (pPhoneNumber: any, pCountryCode = 'AUS') => {
    const mData = {
      number: pPhoneNumber,
      output_format: 'NATIONAL',
      cache_value_days: 0,
      country_iso: pCountryCode,
      get_ported_date: true,
      get_disposable_number: true
    }
    return await this.sendRequest('POST', `${Lookup_URL}phone/validate/v2`, mData, {'Add-Metadata': true})
  }
  sendRequest = async (pRequestMethod: 'POST' | 'GET', pRequestEndPoint: any, pData: any, pHeaders = {}) => {
    const mHeaders = {
      'Auth-Token': this.API_KEY,
      'Content-type': 'application/json',
      ...pHeaders
    }
    const mOptions: {
      url: string
      mode: string
      method: any
      headers: any
      data?: any
    } = {
      url: pRequestEndPoint,
      mode: 'cors',
      method: pRequestMethod,
      headers: mHeaders
    }

    //set parameters depending on the request method
    if (pRequestMethod === 'GET') {
      if (typeof pData === 'string') {
        mOptions.url += `/${pData}`
      } else {
        mOptions.url += '?' + new URLSearchParams(pData).toString()
      }
    } else {
      mOptions.data = JSON.stringify(pData)
    }

    return axios(mOptions)
  }
}
export default Experian
